import json
import requests

conv_ids = [71057, 71058, 71059, 71060, 71061, 71062, 71063, 71064]
statuses = {}

for conv_id in conv_ids:
    url = f"https://mailer.hertzai.com/get-video-conv_id/{conv_id}"
    response = requests.get(url)
    print(f"conv_id: {conv_id}, Status Code: {response.status_code}, Response: {response.text}")
    if response.status_code == 200:
        if response.text == "null":  # Handling null response
            status = 'null response'
        else:
            try:
                response_json = response.json()
                print(f"JSON Response for conv_id {conv_id}: {response_json}")
                status = response_json.get('status', 'Unknown')
            except ValueError as e:
                print(f"Exception for conv_id {conv_id}: {e}")
                status = 'Invalid JSON'
    else:
        status = f'HTTP Error {response.status_code}'

    statuses[conv_id] = status

print(statuses)
